/** Response containing an error. */
export type ErrorResponse = {
  errors?: Array<{
    id?: string;
    status: string;
    code: string;
    title: string;
    detail: string;
    source?: ErrorSourcePointer | ErrorSourceParameter;
    links?: ErrorLinks;
    meta?: {
      [key: string]: unknown;
    };
  }>;
};

/**
 * Parameter
 */
export type ErrorSourceParameter = {
  parameter: string;
};

/**
 * JsonPointer
 */
export type ErrorSourcePointer = {
  pointer: string;
};

/** error links. */
export type ErrorLinks = {
  about?: string;
  associated?:
    | string
    | {
        href?: string;
        meta?: {
          source?: string;
        };
      };
};

