export type PagedDocumentLinks = {
  self: string;
  first?: string;
  next?: string;
};

/** paging information. */
export type PagingInformation = {
  paging: {
    total?: number;
    limit: number;
    nextCursor?: string;
  };
};

/** document links. */
export type DocumentLinks = {
  self: string;
};

/** resource links. */
